// ── 1. Bot Framework JWT: Format-Check ──────────────────────────────────
// Azure Bot Service sendet immer Authorization: Bearer <JWT>.
// Vollständige Signaturprüfung erfordert JWKS-Fetch (separater HTTP-Node).
// Hier: Format-Guard als erste Abwehrlinie gegen anonyme Aufrufe.
const headers = $input.first().json.headers || {};
const authHeader = headers.authorization || headers.Authorization || '';
if (!authHeader.startsWith('Bearer ')) {
  return [{ json: { skip: true, reason: 'no_auth' } }];
}
const jwtParts = authHeader.slice(7).split('.');
if (jwtParts.length !== 3) {
  return [{ json: { skip: true, reason: 'invalid_jwt_format' } }];
}

const body = $input.first().json.body;

// ── 2. SSRF-Schutz: serviceUrl-Allowlist ────────────────────────────────
// Die replyUrl wird aus serviceUrl gebaut. Nur bekannte Microsoft-Domains
// sind erlaubt – verhindert Token-Exfiltration an beliebige URLs.
const ALLOWED_SERVICE_URL_PREFIXES = [
  'https://smba.trafficmanager.net/',
  'https://amer.botframework.com/',
  'https://emea.botframework.com/',
  'https://apac.botframework.com/',
  'https://state.botframework.com/',
  'https://directline.botframework.com/',
];
const serviceUrl = (body.serviceUrl || '').trim();
if (!ALLOWED_SERVICE_URL_PREFIXES.some(prefix => serviceUrl.startsWith(prefix))) {
  return [{ json: { skip: true, reason: 'invalid_service_url' } }];
}

// ── 3. Nur message-Aktivitäten verarbeiten ──────────────────────────────
if (body.type !== 'message' || !body.text) {
  return [{ json: { skip: true, reason: 'not_message' } }];
}

// ── 4. Text kürzen – begrenzt Prompt-Injection-Angriffsfläche ───────────
const MAX_TEXT = 1000;
const text = body.text.trim().slice(0, MAX_TEXT);

return [{
  json: {
    skip: false,
    text: text,
    serviceUrl: serviceUrl,
    conversationId: body.conversation.id,
    activityId: body.id,
    fromName: body.from?.name || 'Unbekannt',
    channelId: body.channelId
  }
}];

