const activity = $('Activity prüfen').first().json;
const token = $('Bot Token holen').first().json.access_token;
const llmReply = $('Ollama LLM').first().json.message?.content || '(keine Antwort erhalten)';

// serviceUrl wurde bereits gegen Allowlist geprüft → sicher für URL-Bau
// Trailing-Slash sicherstellen, conversationId URL-kodieren
const base = activity.serviceUrl.replace(/\/$/, '');
const convId = encodeURIComponent(activity.conversationId);
const replyUrl = `${base}/v3/conversations/${convId}/activities`;

return [{
  json: {
    token: token,
    replyUrl: replyUrl,
    replyBody: {
      type: 'message',
      text: llmReply,
      replyToId: activity.activityId
    }
  }
}];
